module RefModule(  
    input wire clk,  
    input wire CE,  
    input wire T,  
    output reg Q  
);  
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk) begin  
        if (CE) begin  
            if (T)  
                Q <= ~Q;  
        end  
    end  

    initial begin  
        Q = 0;  
    end  
endmodule
